mapper.sql:
(
    yi.native_city_code = #{haidongCityCode}
    or yi.native_county_code in (
        select county.region_code
        from sys_region county
        join sys_region city on county.parent_id = city.id
        where county.deleted = 0
          and city.deleted = 0
          and city.region_code = #{haidongCityCode}
    )
)
